# Server-side token validation
def validate_token(token: str, expected_audience: str):
    # 1. Verify token signature
    if not jwt.verify_signature(token):
        raise Forbidden("Invalid signature")

    # 2. Check audience (must be issued for THIS server)
    if token.audience != expected_audience:
        raise Forbidden("Token not issued for this server")

    # 3. Check expiration
    if token.is_expired:
        raise Forbidden("Token expired")

    # 4. Check scopes
    if not has_required_scope(token.scopes, required_scope):
        raise Forbidden("Missing required scope")

# Server enforces scope on each request
def call_tool(tool_name: str, token_scopes: list[str]):
    required_scope = get_scope_for_tool(tool_name)

    if required_scope not in token_scopes:
        raise HTTP 403 Forbidden  # ← Scope check fails

    # Execute tool
    return execute_tool(tool_name)

