# Tool-level permissions
TOOLS = {
    "read_logs": {"role": "viewer", "scope": "logs:read"},
    "send_email": {"role": "user", "scope": "email:send"},
    "delete_user": {"role": "admin", "scope": "users:delete"}
}

def check_access(user_role: str, tool_name: str):
    required_role = TOOLS[tool_name]["role"]
    if user_role not in required_role:
        raise Forbidden("Insufficient permissions")

# Context-based policy
def can_access_log(user, log_file):
    # User role + data sensitivity + time of day
    if user.role == "admin":
        return True
    if user.role == "viewer" and log_file.sensitivity == "low":
        return True
    if user.role == "viewer" and is_business_hours():
        return True
    return False
